```
     1	/**
     2	 * ORCHESTRATOR EXTENSION — Entry point.
     3	 *
     4	 * Refactored from monolithic orchestrator.ts (1663 lines) into modular structure.
     5	 * Design spec: ORCHESTRATION-UI-DESIGN.md
     6	 * Refactoring plan: ORCHESTRATION-REFACTOR.md
     7	 *
     8	 * This file is the wiring hub. It:
     9	 * - Guards against subagent re-registration (env var check)
    10	 * - Registers before_agent_start handler (injects system prompt, strips tools)
    11	 * - Registers tool_call handler (blocks non-delegate calls)
    12	 * - Delegates tool registration to delegate-tool.ts
    13	 * - Delegates command registration to commands.ts
    14	 */
    15	
    16	import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";
    17	import { isSubagentContext, _batchLoadSubagent, SUBAGENT_ENV_KEY } from "./subagent-runner.ts";
    18	import { clearPlanPanel, generatePlanFromPrompt, setupPlanPanel } from "./plan-panel.ts";
    19	import { shortenLabel } from "../token-saver.ts";
    20	import { registerDelegateTool } from "./delegate-tool.ts";
    21	import { registerCommands } from "./commands.ts";
    22	import { debugLog } from "./debug.ts";
    23	
    24	export default function (pi: ExtensionAPI) {
    25		// ── Guard: Skip registration when loading for a subagent session ──
    26		if (_batchLoadSubagent > 0 || isSubagentContext()) {
    27			debugLog("SKIPPING orchestrator registration (subagent context)", {
    28				batchLoad: _batchLoadSubagent,
    29				envGuard: process.env[SUBAGENT_ENV_KEY],
    30			});
    31			return;
    32		}
    33	
    34		// ── System Prompt: Tell the agent to ALWAYS delegate ──
    35		pi.on("before_agent_start", async (event, ctx) => {
    36			clearPlanPanel(ctx);
    37	
    38			// Strip ALL non-delegation tools from the prompt
    39			if (event.systemPromptOptions?.selectedTools) {
    40				event.systemPromptOptions.selectedTools = ["delegate"];
    41			}
    42	
    43			// Generate and show the full plan upfront from the user's prompt
    44			const prompt = event.prompt || "";
    45			if (prompt) {
    46				const steps = generatePlanFromPrompt(prompt);
    47				setupPlanPanel(shortenLabel(prompt), steps, ctx);
    48			}
    49	
    50			const delegationInstructions = `
    51		## Orchestrator Mode — DELEGATE ONLY
    52	
    53		You are an expert coding assistant operating in **orchestrator mode**. In this mode, your role shifts from direct execution to delegation management — you direct specialist agents who do the hands-on work.
    54	
    55		### Your tool: delegate(specialist, task)
    56	
    57		You have ONE tool: \`delegate(specialist, task)\`.
    58		Call it once per step. Review the output. Then call it again for the next step.
    59	
    60		You do NOT have read, bash, grep, find, edit, or write tools in this mode.
    61		You CANNOT access files or run commands directly.
    62	
    63		### Specialist roster:
    64		- **scout** — Fast codebase investigation (read-only)
    65		- **coder** — Implementation (read/write/bash)
    66		- **reviewer** — Code review (read-only, thorough)
    67		- **researcher** — Question answering (read-only)
    68		- **writer** — Documentation (read/write)
    69	
    70		### Workflow:
    71		1. Analyze the request
    72		2. Call delegate(scout, "investigate ...") — read output
    73		3. Call delegate(coder, "implement ... based on: [scout output]") — read output
    74		4. Call delegate(reviewer, "review ... based on: [coder output]") — read output
    75		5. Synthesize all results into final answer
    76	
    77		You decide next step AFTER seeing previous result. NOT before.`;
    78	
    79			return {
    80				systemPrompt: event.systemPrompt + delegationInstructions,
    81			};
    82		});
    83	
    84		// ── Safety net: Block non-delegation tool calls ──
    85		pi.on("tool_call", async (event, ctx) => {
    86			if (_batchLoadSubagent > 0) return; // Don't block subagent tools
    87			if (event.toolName !== "delegate") {
    88				return { block: true, reason: `Orchestrator mode: use delegate() instead of ${event.toolName}` };
    89			}
    90		});
    91	
    92		// ── Register tools and commands ──
    93		registerDelegateTool(pi);
    94		registerCommands(pi);
    95	}
```

**Total:** 95 lines (including blank lines). Lines 1–95 complete, no truncation. The file is 95 lines long.

